import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { analyticsApi } from '../api/analytics';
import Card from './Card';

const METRICS = [
  { key: 'registered_onboarded', label: 'Registered Onboarded' },
  { key: 'linked_accounts', label: 'Linked Accounts' },
  { key: 'total_advance_applications', label: 'Total Advance Applications' },
  { key: 'total_advance_applicants', label: 'Total Advance Applicants' },
  { key: 'total_micro_financing_applications', label: 'Total Micro Financing Applications' },
  { key: 'total_micro_financing_applicants', label: 'Total Micro Financing Applicants' },
  { key: 'total_personal_finance_application', label: 'Total Personal Finance Application' },
  { key: 'total_personal_finance_applicants', label: 'Total Personal Finance Applicants' }
];

const DAY_NAMES = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

const WeeklyComparison: React.FC = () => {
  const [selectedDays, setSelectedDays] = useState([0]); // Default to Sunday
  const [selectedMonth, setSelectedMonth] = useState<string | null>(null);
  const [selectedMetric, setSelectedMetric] = useState('linked_accounts');

  const { data, isLoading, error } = useQuery({
    queryKey: ['weekly-comparison', selectedDays, selectedMonth, selectedMetric],
    queryFn: () => analyticsApi.getWeeklyComparison({
      days: selectedDays.join(','),
      month: selectedMonth || undefined,
      metric: selectedMetric
    })
  });

  const handleDayToggle = (dayIndex: number) => {
    setSelectedDays(prev => {
      if (prev.includes(dayIndex)) {
        const filtered = prev.filter(d => d !== dayIndex);
        return filtered.length === 0 ? [dayIndex] : filtered; // Keep at least one day
      } else {
        return [...prev, dayIndex];
      }
    });
  };

  // Extract available months from data
  const availableMonths = data?.series?.[0]?.points?.map((p: any) => p.month) || [];

  // Prepare chart data
  const chartData = data?.series?.[0]?.points?.map((point: any) => ({
    month: point.month,
    ...data.series.reduce((acc: any, series: any) => {
      acc[series.label] = series.points.find((p: any) => p.month === point.month)?.value || 0;
      return acc;
    }, {})
  })) || [];

  const colors = ['#3B82F6', '#EF4444', '#10B981', '#F59E0B', '#8B5CF6', '#EC4899', '#6B7280'];

  return (
    <Card title="Weekly Comparison (Cross-Month Weekly Analysis)">
      <div className="space-y-6">
        {/* Metric Selector */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Select Metric
          </label>
          <select
            value={selectedMetric}
            onChange={(e) => setSelectedMetric(e.target.value)}
            className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500"
          >
            {METRICS.map(metric => (
              <option key={metric.key} value={metric.key}>
                {metric.label}
              </option>
            ))}
          </select>
        </div>

        {/* Day Chips */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Select Days
          </label>
          <div className="flex flex-wrap gap-2">
            {DAY_NAMES.map((day, index) => (
              <button
                key={index}
                onClick={() => handleDayToggle(index)}
                className={`px-3 py-1 rounded-full text-sm font-medium transition-colors ${
                  selectedDays.includes(index)
                    ? 'bg-blue-500 text-white'
                    : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                }`}
              >
                {day}
              </button>
            ))}
          </div>
        </div>

        {/* Month Scope */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Month Scope
          </label>
          <select
            value={selectedMonth || ''}
            onChange={(e) => setSelectedMonth(e.target.value || null)}
            className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500"
          >
            <option value="">All Months Combined</option>
            {availableMonths.map((month: string) => (
              <option key={month} value={month}>
                {month}
              </option>
            ))}
          </select>
        </div>

        {/* Results */}
        {isLoading && (
          <div className="flex justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500"></div>
          </div>
        )}

        {error && (
          <div className="bg-red-50 border border-red-200 rounded-md p-4">
            <p className="text-red-800">Error loading data: {(error as Error)?.message || 'Unknown error'}</p>
          </div>
        )}

        {data && data.series && data.series.length > 0 ? (
          <div className="space-y-4">
            {/* Chart */}
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="month" />
                  <YAxis />
                  <Tooltip />
                  {data.series.map((series: any, index: number) => (
                    <Line
                      key={series.label}
                      type="monotone"
                      dataKey={series.label}
                      stroke={colors[index % colors.length]}
                      strokeWidth={2}
                      dot={{ r: 4 }}
                    />
                  ))}
                </LineChart>
              </ResponsiveContainer>
            </div>

            {/* Legend */}
            <div className="flex flex-wrap gap-4">
              {data.series.map((series: any, index: number) => (
                <div key={series.label} className="flex items-center space-x-2">
                  <div 
                    className="w-3 h-3 rounded-full"
                    style={{ backgroundColor: colors[index % colors.length] }}
                  ></div>
                  <span className="text-sm text-gray-600">{series.label}</span>
                </div>
              ))}
            </div>

            {/* Summary Table */}
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Day
                    </th>
                    {chartData.map((item: any) => (
                      <th key={item.month} className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {item.month}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {data.series.map((series: any) => (
                    <tr key={series.label}>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                        {series.label}
                      </td>
                      {series.points.map((point: any) => (
                        <td key={point.month} className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                          {point.value.toLocaleString()}
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Footer Info */}
            <div className="text-sm text-gray-600 bg-gray-50 p-3 rounded-md">
              <p>
                <strong>Day Selected:</strong> {selectedDays.map(d => DAY_NAMES[d]).join(', ')}
              </p>
              <p>
                <strong>Month Scope:</strong> {selectedMonth || 'All Months Combined'}
              </p>
            </div>

            {/* Analysis Text */}
            <div className="bg-blue-50 p-4 rounded-md">
              <p className="text-sm text-gray-700">
                {selectedMonth ? 
                  `Analysis shows performance for ${selectedDays.map(d => DAY_NAMES[d]).join(', ')} within ${selectedMonth}` :
                  `Cross-month analysis comparing ${selectedDays.map(d => DAY_NAMES[d]).join(', ')} performance across all available months`
                }
              </p>
            </div>
          </div>
        ) : (
          !isLoading && (
            <div className="text-center py-8">
              <p className="text-gray-500 mb-4">No data available for the selected criteria</p>
              <button className="bg-blue-500 text-white px-4 py-2 rounded-md hover:bg-blue-600">
                Go to Data Entry
              </button>
            </div>
          )
        )}
      </div>
    </Card>
  );
};

export default WeeklyComparison;
